    function getProducerById(producerId: string) {
        if (!producerId)
            return null;
        if (currentProducerProfile.id === producerId)
            return currentProducerProfile;
        return producerProfiles.find((profile) => profile.id === producerId) || null;
    }
    async function getAlbumUploadUser() {
        let sessionUser: SupabaseUser | null = null;
        try {
            const { data: { session }, error: sessionError, } = await supabase.auth.getSession();
            if (sessionError) {
            }
            sessionUser = session?.user || null;
        }
        catch (error) {
        }
        const uploadUser = sessionUser || albumUploadUserRef.current || user;
        if (!uploadUser?.id) {
            throw new Error("Sign in first before uploading an album.");
        }
        albumUploadUserRef.current = uploadUser;
        setUser((previous) => previous || uploadUser);
        return uploadUser;
    }
    async function getFreshVideoStorageUploadUser() {
        const { data: { session }, error: sessionError, } = await supabase.auth.getSession();
        let activeSession = session;
        if (sessionError) {
            throw new Error(`Supabase auth check failed before video upload: ${sessionError.message}`);
        }
        const expiresAtMs = activeSession?.expires_at ? activeSession.expires_at * 1000 : 0;
        if (activeSession?.refresh_token && expiresAtMs && expiresAtMs - Date.now() < 60000) {
            const { data: refreshData, error: refreshError } = await supabase.auth.refreshSession();
            if (refreshError) {
                throw new Error(`Supabase auth refresh failed before video upload: ${refreshError.message}`);
            }
            activeSession = refreshData.session;
        }
        if (!activeSession?.access_token || !activeSession.user?.id) {
            throw new Error("You must log in again before uploading videos to Supabase Storage.");
        }
        setUser((previous) => previous || activeSession.user);
        return {
            user: activeSession.user,
            accessToken: activeSession.access_token,
        };
    }
    async function uploadAudioToSupabase(file: File, songDetails: Pick<UploadForm, "title" | "artist" | "type" | "cover" | "producerId">, uploadUser?: SupabaseUser | null, albumId = "") {
        const fileError = getAudioFileError(file);
        if (fileError) {
            throw new Error(fileError);
        }
        let sessionUser = uploadUser || null;
        if (!sessionUser) {
            const { data: { session }, error: sessionError, } = await supabase.auth.getSession();
            if (sessionError || !session?.access_token || !session.user) {
                throw new Error("You must log in again before uploading.");
            }
            sessionUser = session.user;
        }
        if (!sessionUser?.id) {
            throw new Error("You must log in again before uploading.");
        }
        setUploadStatus("Preparing upload...");
        setUploadProgress(4);
        setUploadStatus("Uploading audio...");
        const sessionUserId = sessionUser.id;
        const formData = new FormData();
        formData.append("file", file);
        formData.append("sessionUserId", sessionUserId);
        formData.append("userId", sessionUserId);
        formData.append("title", songDetails.title);
        formData.append("artist", songDetails.artist);
        formData.append("category", "New Releases");
        formData.append("type", songDetails.type);
        formData.append("cover_url", getArtworkUrl(songDetails.cover));
        if (albumId) {
            formData.append("album_id", albumId);
        }
        const producer = getProducerById(songDetails.producerId);
        formData.append("producer_id", producer?.id || "");
        formData.append("producer", producer?.name || "");
        const songInsertPayloadPreview = {
            user_id: sessionUserId,
            title: songDetails.title,
            artist: songDetails.artist,
            category: "New Releases",
            type: songDetails.type,
            cover_url: getArtworkUrl(songDetails.cover),
            producer_id: producer?.id || "",
            producer: producer?.name || "",
            album_id: albumId || "",
        };
        console.error("INSERT USER ID:", songInsertPayloadPreview.user_id);
        console.error("AUTH USER ID:", sessionUserId);
        console.error("FULL INSERT PAYLOAD:", songInsertPayloadPreview);
        let response: Response;
        try {
            response = await fetch("/api/upload-audio", {
                method: "POST",
                body: formData,
            });
        }
        catch (error) {
            const details = getErrorDetails(error);
            throw new Error(`Audio upload route could not be reached.${details ? ` ${details}` : ""}`);
        }
        const responseText = await response.text();
        let uploadResult: {
            publicUrl?: string;
            storagePath?: string;
            song?: SongTableRow;
            error?: string;
            details?: unknown;
        } = {};
        if (responseText) {
            try {
                uploadResult = JSON.parse(responseText) as typeof uploadResult;
            }
            catch {
                uploadResult = { error: responseText };
            }
        }
        if (!response.ok) {
            const detailText = typeof uploadResult.details === "string"
                ? uploadResult.details
                : uploadResult.details
                    ? JSON.stringify(uploadResult.details)
                    : "";
            const responseDetails = uploadResult.details && typeof uploadResult.details === "object" ? uploadResult.details as Record<string, unknown> : {};
            const responseInsertPayload = responseDetails.insertPayload && typeof responseDetails.insertPayload === "object"
                ? responseDetails.insertPayload as Record<string, unknown>
                : songInsertPayloadPreview;
            console.error("INSERT USER ID:", responseDetails.insertUserId || responseInsertPayload.user_id || songInsertPayloadPreview.user_id);
            console.error("AUTH USER ID:", responseDetails.authUserId || sessionUserId);
            console.error("FULL INSERT PAYLOAD:", responseInsertPayload);
            console.error("SONG INSERT FAILED", uploadResult.error || response.statusText, detailText);
            console.error("[music upload] INSERT FAILED public.songs:", uploadResult.error || response.statusText, detailText);
            throw new Error([uploadResult.error || `Audio upload failed with HTTP ${response.status}.`, detailText]
                .filter(Boolean)
                .join(" "));
        }
        if (!uploadResult.publicUrl) {
            throw new Error("Supabase did not return a public URL for the uploaded audio.");
        }
        if (!uploadResult.song) {
            throw new Error("Supabase uploaded the audio, but the server did not return the saved songs table row.");
        }
        setUploadProgress(98);
        setUploadStatus("Finishing upload...");
        setUploadProgress(100);
        return mapSongRowToSong(uploadResult.song);
    }
    async function uploadVideoToSupabase(file: File, videoDetails: Pick<VideoUploadForm, "title" | "creator" | "category" | "cover" | "producerId">, uploadUser?: SupabaseUser | null, albumId = "") {
        const fileError = getVideoFileError(file);
        if (fileError) {
            throw new Error(fileError);
        }
        if (uploadUser?.id) {
            albumUploadUserRef.current = uploadUser;
        }
        updateVideoUploadDebug({
            currentStep: "Checking Supabase auth session for video upload",
            lastError: "",
        });
        const { user: sessionUser } = await getFreshVideoStorageUploadUser();
        const producer = getProducerById(videoDetails.producerId);
        const producerId = producer?.id || videoDetails.producerId || "";
        const metadataTargetUrl = typeof window !== "undefined"
            ? new URL("/api/video-upload", window.location.origin).toString()
            : "/api/video-upload";
        const storagePath = buildVideoStoragePath(sessionUser.id, file);
        const contentType = getVideoUploadContentType(file);
        const codecInfo = await inspectVideoFileCodecInfo(file);
        setVideoUploadStep("Preparing video...", 4);
        updateVideoUploadDebug({
            uploadMethod: "Browser direct Supabase Storage upload, server metadata insert",
            supabaseUrl: process.env.NEXT_PUBLIC_SUPABASE_URL || "",
            uploadTargetUrl: process.env.NEXT_PUBLIC_SUPABASE_URL || "",
            bucket: VIDEOS_STORAGE_BUCKET,
            fileSize: String(file.size),
            fileName: file.name,
            selectedFileName: file.name,
            selectedFileSize: String(file.size),
            hasFileObject: true,
            currentStep: "Prepared browser direct Supabase Storage upload",
            lastError: "",
            fullErrorJson: "",
            requestContainsDigitalMusicDatabase: false,
            requestContainsSupabaseCo: true,
            requestLooksLikeVercelFunction: false,
            requestLooksLikeAppServer: false,
            requestMethod: "POST",
            requestBodyType: "File direct to Supabase Storage",
            requestBodySize: String(file.size),
            insertUserId: sessionUser.id,
            authUserId: sessionUser.id,
            insertUserMatchesAuth: "true",
            sourceLocation: "app/page.tsx uploadVideoToSupabase -> supabase.storage.upload(file)",
        });
        setVideoUploadStep("Uploading video directly to Supabase Storage...", 12);
        console.log("SUPABASE URL:", process.env.NEXT_PUBLIC_SUPABASE_URL);
        console.log("UPLOAD TARGET:", process.env.NEXT_PUBLIC_SUPABASE_URL);
        console.log("SELECTED FILE SIZE:", file.size);
        console.log("DIRECT VIDEO UPLOAD PREPARED", {
            fileName: file.name,
            fileSize: file.size,
            storagePath,
            metadataTargetUrl,
            videoCodec: codecInfo.videoCodec,
            audioCodec: codecInfo.audioCodec,
            mobileCompatible: codecInfo.mobileCompatible,
        });
        let savedStoragePath = storagePath;
        let publicUrl = "";
        try {
            const storageUpload = await supabase.storage.from(VIDEOS_STORAGE_BUCKET).upload(storagePath, file, {
                cacheControl: "3600",
                contentType,
                upsert: true,
            });
            if (storageUpload.error) {
                throw storageUpload.error;
            }
            savedStoragePath = storageUpload.data?.path || storagePath;
            const { data: publicUrlData } = supabase.storage.from(VIDEOS_STORAGE_BUCKET).getPublicUrl(savedStoragePath);
            publicUrl = publicUrlData.publicUrl || "";
        }
        catch (storageError) {
            const storageErrorMessage = storageError instanceof Error ? storageError.message : String(storageError || "");
            const looksLikeCorsOrNetworkFailure = /failed to fetch|network|cors|access-control-allow-origin/i.test(storageErrorMessage);
            const canUseServerFallback = looksLikeCorsOrNetworkFailure && file.size <= SERVER_VIDEO_UPLOAD_FALLBACK_MAX_BYTES;
            updateVideoUploadDebug({
                currentStep: canUseServerFallback ? "Direct Supabase Storage upload failed; trying server fallback" : "Supabase Storage upload failed",
                lastError: looksLikeCorsOrNetworkFailure ? VIDEO_STORAGE_CORS_FIX_MESSAGE : storageErrorMessage || "Supabase Storage video upload failed.",
                fullErrorJson: stringifyUploadDebugError(storageError),
                requestLooksLikeVercelFunction: canUseServerFallback,
                requestBodyType: canUseServerFallback ? "Server fallback FormData video upload" : "File direct to Supabase Storage",
            });
            if (!looksLikeCorsOrNetworkFailure) {
                throw new Error(storageErrorMessage || "Supabase Storage video upload failed.");
            }
            if (file.size > SERVER_VIDEO_UPLOAD_FALLBACK_MAX_BYTES) {
                throw new Error(`${VIDEO_STORAGE_CORS_FIX_MESSAGE} Vercel cannot proxy this ${Math.ceil(file.size / 1024 / 1024)} MB video upload.`);
            }
            setVideoUploadStep("Direct storage blocked. Uploading through server fallback...", 30);
            const fallbackForm = new FormData();
            fallbackForm.set("file", file);
            fallbackForm.set("sessionUserId", sessionUser.id);
            fallbackForm.set("userId", sessionUser.id);
            const fallbackResponse = await fetch("/api/video-upload", {
                method: "POST",
                body: fallbackForm,
            });
            const fallbackText = await fallbackResponse.text();
            let fallbackResult: {
                error?: string;
                details?: unknown;
                publicUrl?: string;
                storagePath?: string;
                fileName?: string;
                fileSize?: number | null;
                contentType?: string;
            } = {};
            if (fallbackText) {
                try {
                    fallbackResult = JSON.parse(fallbackText) as typeof fallbackResult;
                }
                catch {
                    fallbackResult = { error: fallbackText };
                }
            }
            if (!fallbackResponse.ok || !fallbackResult.publicUrl || !fallbackResult.storagePath) {
                const detailText = typeof fallbackResult.details === "string"
                    ? fallbackResult.details
                    : fallbackResult.details
                        ? JSON.stringify(fallbackResult.details)
                        : "";
                throw new Error([fallbackResult.error || `Server fallback upload failed with HTTP ${fallbackResponse.status}.`, detailText]
                    .filter(Boolean)
                    .join(" "));
            }
            savedStoragePath = fallbackResult.storagePath;
            publicUrl = fallbackResult.publicUrl;
            updateVideoUploadDebug({
                uploadMethod: "Server fallback video upload, server metadata insert",
                uploadTargetUrl: typeof window !== "undefined" ? new URL("/api/video-upload", window.location.origin).toString() : "/api/video-upload",
                currentStep: "Server fallback uploaded video to Supabase Storage",
                requestContainsDigitalMusicDatabase: true,
                requestContainsSupabaseCo: false,
                requestLooksLikeVercelFunction: true,
                requestLooksLikeAppServer: true,
                requestMethod: "POST",
                requestBodyType: "FormData video to server fallback",
                requestBodySize: String(file.size),
                fullErrorJson: "",
            });
        }
        if (!publicUrl) {
            throw new Error("Supabase did not return a public URL for the uploaded video.");
        }
        setVideoUploadStep("Saving video metadata...", 88);
        const metadataPayload = {
            sessionUserId: sessionUser.id,
            userId: sessionUser.id,
            artist_id: sessionUser.id,
            title: videoDetails.title,
            description: videoDetails.creator,
            artist_name: videoDetails.creator,
            category: videoDetails.category,
            cover_url: videoDetails.cover || DEFAULT_COVER,
            thumbnail_url: videoDetails.cover || DEFAULT_COVER,
            producer: producer?.name || "",
            producer_name: producer?.name || "",
            producer_id: producerId || "",
            producer_profile_id: producerId || "",
            album_id: albumId || "",
            publicUrl,
            storagePath: savedStoragePath,
            fileName: file.name || "video.mp4",
            fileSize: file.size,
            contentType,
            video_codec: codecInfo.videoCodec || null,
            audio_codec: codecInfo.audioCodec || null,
            mobile_compatible: codecInfo.mobileCompatible,
        };
        const response = await fetch("/api/video-upload", {
            method: "POST",
            headers: {
                "content-type": "application/json",
            },
            body: JSON.stringify(metadataPayload),
        });
        const responseText = await response.text();
        let uploadResult: {
            error?: string;
            details?: unknown;
            publicUrl?: string;
            storagePath?: string;
            fileName?: string;
            fileSize?: number | null;
            contentType?: string;
            video?: VideoTableRow | null;
        } = {};
        if (responseText) {
            try {
                uploadResult = JSON.parse(responseText) as typeof uploadResult;
            }
            catch {
                uploadResult = { error: responseText };
            }
        }
        if (!response.ok) {
            const detailText = typeof uploadResult.details === "string"
                ? uploadResult.details
                : uploadResult.details
                    ? JSON.stringify(uploadResult.details)
                    : "";
            console.error("VIDEO UPLOAD API FAILED", uploadResult.error || response.statusText, detailText);
            updateVideoUploadDebug({
                currentStep: "Video metadata insert failed",
                lastError: [uploadResult.error || response.statusText, detailText].filter(Boolean).join(" "),
                fullErrorJson: responseText || stringifyUploadDebugError(uploadResult),
                fullInsertPayload: JSON.stringify(metadataPayload, null, 2),
            });
            throw new Error([uploadResult.error || `Video upload failed with HTTP ${response.status}.`, detailText]
                .filter(Boolean)
                .join(" "));
        }
        if (!uploadResult.publicUrl || !uploadResult.storagePath) {
            throw new Error("Video uploaded, but the server did not return a public URL and storage path.");
        }
        const savedVideo = uploadResult.video;
        if (!savedVideo) {
            throw new Error("Supabase uploaded the video, but the server did not return the saved videos table row.");
        }
        setVideoUploadStep("Finishing upload...", 98);
        setVideoUploadStep("Video upload complete.", 100);
        updateVideoUploadDebug({
            currentStep: "Video upload complete.",
            lastError: "",
            uploadTargetUrl: metadataTargetUrl,
            requestMethod: "POST",
            requestBodyType: "JSON metadata to server route",
            requestBodySize: String(JSON.stringify(metadataPayload).length),
            insertUserId: String(savedVideo.user_id || sessionUser.id),
            authUserId: sessionUser.id,
            insertUserMatchesAuth: String(String(savedVideo.user_id || sessionUser.id) === sessionUser.id),
            fullInsertPayload: JSON.stringify(savedVideo, null, 2),
        });
        return mapVideoRowToVideoItem(savedVideo);
    }
    async function copyStorageSetupSql() {
        try {
            await navigator.clipboard.writeText(STORAGE_SETUP_SQL);
            setStorageSetupCopied(true);
            window.setTimeout(() => setStorageSetupCopied(false), 1800);
        }
        catch {
            setUploadError("Copy failed. Your browser blocked clipboard access.");
        }
    }
    async function addUploadedSong(event: FormEvent<HTMLFormElement>) {
        event.preventDefault();
        setUploadError("");
        setStorageSetupCopied(false);
        const title = uploadForm.title.trim();
        const artist = uploadForm.artist.trim();
        if (!title || !artist) {
            setUploadError("Add a song title and artist name first.");
            return;
        }
        const fileError = getAudioFileError(uploadFile);
        if (fileError) {
            setUploadError(fileError);
            return;
        }
        setUploadBusy(true);
        setUploadProgress(1);
        setUploadStatus("Starting upload...");
        let uploadGuardActive = false;
        let uploadGuardKey = "";
        try {
            const selectedFile = uploadFile;
            if (!selectedFile) {
                setUploadError("Choose an MP3, WAV, or M4A audio file.");
                return;
            }
            uploadGuardKey = getUploadGuardKey("song", title, [selectedFile]);
            uploadGuardActive = beginUploadGuard(uploadGuardKey, "This song upload is already running.");
            if (!uploadGuardActive)
                return;
            const newSong = await uploadAudioToSupabase(selectedFile, {
                title,
                artist,
                type: uploadForm.type,
                cover: uploadForm.cover,
                producerId: uploadForm.producerId,
            });
            const databaseSongs = await reloadSongLibraryFromSupabase();
            const savedSong = databaseSongs.find((song) => song.id === newSong.id) || newSong;
            saveToLibrary(savedSong);
            setCurrentSong(savedSong);
            setView("Library");
            setShowUpload(false);
            setUploadForm({
                title: "",
                artist: "",
                type: "Beats",
                cover: "",
                producerId: "",
            });
            setUploadFile(null);
            setUploadStatus("");
        }
        catch (error) {
            const message = getStorageErrorMessage(error, "audio");
            setUploadError(message);
            setUploadStatus("");
            reportPlatformError("upload", "song-upload", message, { title, artist });
        }
        finally {
            if (uploadGuardActive) {
                endUploadGuard(uploadGuardKey);
            }
            setUploadBusy(false);
        }
    }
    async function saveAccountRole(nextRole: AccountRole) {
        if (!user?.id) {
            showToast("Log in before changing account type.", "error");
            return;
        }
        const previousRole = accountRole;
        setAccountRole(nextRole);
        try {
            const response = await fetch("/api/producers", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    action: "save-account-role",
                    userId: user.id,
                    accountType: nextRole.toLowerCase(),
                    skipProducerProfile: isPlatformOwner,
                    producerProfileId: currentProducerProfile.id,
                    name: producerProfileForm.name.trim() || currentProducerProfile.name,
                    avatar: producerProfileForm.avatar.trim() || currentProducerProfile.avatar,
                    banner: producerProfileForm.banner.trim() || currentProducerProfile.banner,
                    bio: producerProfileForm.bio.trim() || currentProducerProfile.bio,
                    tagline: producerProfileForm.tagline.trim() || currentProducerProfile.tagline,
                }),
            });
            const data = (await response.json().catch(() => ({}))) as {
                error?: string;
                profile?: ProducerProfileTableRow;
                profileWarning?: string;
            };
            if (!response.ok) {
                setAccountRole(previousRole);
                showToast(data.error || "Account type could not be saved.", "error");
                return;
            }
            if (data.profile) {
                const savedProfile = mapProducerProfileRow(data.profile);
                setProducerProfiles((previous) => {
                    const remaining = previous.filter((profile) => profile.id !== savedProfile.id && profile.userId !== savedProfile.userId);
                    return [savedProfile, ...remaining];
                });
                setActiveProducerId(savedProfile.id);
                setProducerProfileForm({
                    name: savedProfile.name,
                    avatar: savedProfile.avatar,
                    banner: savedProfile.banner,
                    bio: savedProfile.bio,
                    tagline: savedProfile.tagline,
                    website: savedProfile.website,
                });
            }
            if (data.profileWarning) {
                showToast(`${nextRole} mode saved through creator profile. Profiles account_type needs setup.`, "info");
            }
            else {
                showToast(`${nextRole} account mode saved.`, "success");
            }
        }
        catch (error) {
            setAccountRole(previousRole);
            showToast("Account type could not be saved. Check your connection and try again.", "error");
        }
    }
    async function saveProducerProfile(event?: FormEvent<HTMLFormElement> | null, profileUser?: SupabaseUser | null) {
        event?.preventDefault();
        const ownerUser = profileUser || user;
        if (!ownerUser?.id) {
            showToast("Log in before saving a producer profile.", "error");
            return currentProducerProfile;
        }
        const nextProfile = {
            id: currentProducerProfile.id,
            userId: ownerUser.id,
            name: producerProfileForm.name.trim() || currentProducerProfile.name,
            avatar: producerProfileForm.avatar.trim() || currentProducerProfile.avatar,
            banner: producerProfileForm.banner.trim() || currentProducerProfile.banner,
            bio: producerProfileForm.bio.trim() || currentProducerProfile.bio,
            tagline: producerProfileForm.tagline.trim() || currentProducerProfile.tagline,
            website: producerProfileForm.website.trim() || currentProducerProfile.website,
        };
        const response = await fetch("/api/producers", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
                action: "upsert-profile",
                ...nextProfile,
            }),
        });
        const data = (await response.json().catch(() => ({}))) as {
            profile?: ProducerProfileTableRow;
            error?: string;
        };
        if (!response.ok || !data.profile) {
            showToast(data.error || "Producer profile save failed.", "error");
            return currentProducerProfile;
        }
        const savedProfile = mapProducerProfileRow(data.profile);
        setProducerProfiles((previous) => {
            const remaining = previous.filter((profile) => profile.id !== savedProfile.id && profile.userId !== savedProfile.userId);
            return [savedProfile, ...remaining];
        });
        setActiveProducerId(savedProfile.id);
        setProducerProfileForm({
            name: savedProfile.name,
            avatar: savedProfile.avatar,
            banner: savedProfile.banner,
            bio: savedProfile.bio,
            tagline: savedProfile.tagline,
            website: savedProfile.website,
        });
        showToast("Producer profile saved.", "success");
        return savedProfile;
    }
    async function saveProducerBeatMetadata(song: Song, profile: ProducerProfile) {
        const response = await fetch("/api/producers", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
                action: "upsert-beat",
                songId: song.id,
                producerId: profile.id,
                producerUserId: profile.userId,
                producerName: profile.name,
                title: song.title,
                category: song.type || "Beats",
                cover: song.cover,
                audioUrl: song.audio,
                storagePath: song.audioPath || "",
                license: producerLicense,
                leasePrice: producerLeasePrice,
                exclusivePrice: producerExclusivePrice,
                splitPercentage: clampProducerSplitShare(producerSplitPercentage),
            }),
        });
        const data = (await response.json().catch(() => ({}))) as {
            beat?: ProducerBeatTableRow;
            error?: string;
        };
        if (!response.ok || !data.beat) {
            throw new Error(data.error || "Producer beat metadata save failed.");
        }
        const beat = mapProducerBeatRow(data.beat);
        setProducerBeats((previous) => [beat, ...previous.filter((item) => item.id !== beat.id && item.songId !== beat.songId)]);
        return beat;
    }
