    function renderSharedVideoPlayer() {
        if (!activeVideo)
            return null;
        const showMobileIncompatibleFallback = mobilePlaybackEnvironment && isVideoMarkedMobileIncompatible(activeVideo);
        return (<section className="video-player-panel global-video-player" ref={videoPreviewRef}>
        {showMobileIncompatibleFallback ? (<div className="video-mobile-incompatible-panel">
            <Film size={42}/>
            <strong>Mobile incompatible video</strong>
            <span>This video must be re-uploaded as MP4 H.264/AAC for mobile.</span>
          </div>) : activeVideoPlaybackUrl ? (<video key={activeVideo.id || activeVideoPlaybackUrl} ref={mainVideoRef} controls src={activeVideoPlaybackUrl} muted={false} autoPlay={false} playsInline preload="metadata" poster={activeVideo.cover} onClick={() => void handleNativeVideoTap()} onLoadedMetadata={(event) => {
                updateVideoDuration(event);
                logVideoElementState("loadedmetadata event", event.currentTarget);
            }} onDurationChange={(event) => {
                updateVideoDuration(event);
                logVideoElementState("durationchange event", event.currentTarget);
            }} onCanPlay={(event) => {
                logVideoElementState("canplay event", event.currentTarget);
                handleVideoCanPlay();
            }} onCanPlayThrough={(event) => {
                logVideoElementState("canplaythrough event", event.currentTarget);
            }} onPlaying={(event) => {
                logVideoElementState("playing event", event.currentTarget);
            }} onStalled={(event) => {
                logVideoElementState("stalled event", event.currentTarget);
            }} onWaiting={(event) => {
                logVideoElementState("waiting event", event.currentTarget);
            }} onTimeUpdate={updateVideoProgress} onPlay={handleVideoPlay} onPause={(event) => {
                logVideoElementState("pause listener event", event.currentTarget);
                handleVideoPause();
            }} onEnded={handleVideoEnded} onError={(event) => {
                logVideoElementState("error event", event.currentTarget, {
                    exactError: event.currentTarget.error?.message || "",
                });
                if (mobilePlaybackEnvironment && event.currentTarget.error?.code === 4) {
                    setVideoPlaying(false);
                    const incompatibleUpdate = {
                        videoCodec: activeVideo.videoCodec || activeVideo.video_codec || "av01",
                        video_codec: activeVideo.videoCodec || activeVideo.video_codec || "av01",
                        mobileCompatible: false,
                        mobile_compatible: false,
                    };
                    setActiveVideo((previous) => previous?.id === activeVideo.id
                        ? normalizeVideoForPlayback({ ...previous, ...incompatibleUpdate })
                        : previous);
                    setVideos((previous) => previous.map((video) => video.id === activeVideo.id
                        ? normalizeVideoForPlayback({ ...video, ...incompatibleUpdate })
                        : video));
                    event.currentTarget.pause();
                    event.currentTarget.removeAttribute("src");
                    event.currentTarget.load();
                }
                console.error("[mobile video] exact media error", {
                    selectedVideoId: activeVideo.id,
                    title: activeVideo.title,
                    finalVideoUrl: activeVideoPlaybackUrl,
                    src: event.currentTarget.src,
                    currentSrc: event.currentTarget.currentSrc,
                    readyState: event.currentTarget.readyState,
                    networkState: event.currentTarget.networkState,
                    errorCode: event.currentTarget.error?.code || null,
                    errorMessage: event.currentTarget.error?.message || "",
                });
            }}/>) : (<div className="video-missing-source">This video is missing a playable URL.</div>)}
        <div className="video-player-copy">
          <span>{activeVideo.category}</span>
          <h3>{activeVideo.title}</h3>
          <p>{activeVideo.creator}</p>
          {isVideoMarkedMobileIncompatible(activeVideo) ? (<p className="mobile-video-incompatible">{showMobileIncompatibleFallback ? "This video must be re-uploaded as MP4 H.264/AAC for mobile." : "This video may not play on some mobile devices."}</p>) : null}
          <div className="video-player-actions">
            <button onClick={() => playAdjacentVideo("previous")} type="button" disabled={getVideoPlaybackList().length < 2}>
              <SkipBack size={16} fill="currentColor"/>
              Previous Video
            </button>
            <button onClick={() => playAdjacentVideo("next")} type="button" disabled={getVideoPlaybackList().length < 2}>
              <SkipForward size={16} fill="currentColor"/>
              Next Video
            </button>
          </div>
        </div>
      </section>);
    }
